import{_ as e,o as a,c as n,ae as s}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Criteo Advanced Configuration","description":"","frontmatter":{"title":"Criteo Advanced Configuration","slug":"criteo-advanced"},"headers":[],"relativePath":"developer-hub/criteo-advanced.md","filePath":"developer-hub/criteo-advanced.md"}'),i={name:"developer-hub/criteo-advanced.md"};function o(r,t,p,d,l,c){return a(),n("div",null,[...t[0]||(t[0]=[s(`<p><a href="http://www.criteo.com" target="_blank" rel="noreferrer">Criteo</a> is the global leader in Performance Display. Criteo is a global technology company that enables brands and retailers to connect more shoppers to the things they need and love.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>For basic Criteo configuration, visit our <a href="./criteo.html">Marketer Hub guide</a>.</p></div><h2 id="server-to-server-tracking-links" tabindex="-1">Server to server tracking links <a class="header-anchor" href="#server-to-server-tracking-links" aria-label="Permalink to &quot;Server to server tracking links&quot;">​</a></h2><p>If you just need a server to server tracking link, you can use the same flow as, above.</p><p>However, at the end, add the following:</p><ul><li><code>&amp;%24s2s=true</code> at the end of your link, so we know it’s a server to server link.</li><li>Device ID macro <code>&amp;%24idfa=</code> for iOS devices OR <code>&amp;%24aaid=</code> for Android devices.</li><li>Device OS macro <code>%24os=</code> for IOS or ANDROID.</li><li>Send IP client’s address via URL parameter or HTTP Header.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- IP Header to override the IP information on click. e.g. \`x-ip-override: {IP ADDRESS}\`.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        - IP URL parameter \`&amp;device_ip={IP_Address}\`.</span></span></code></pre></div><h2 id="add-static-track-transaction" tabindex="-1">Add Static Track Transaction <a class="header-anchor" href="#add-static-track-transaction" aria-label="Permalink to &quot;Add Static Track Transaction&quot;">​</a></h2><p>Static Track Transaction is a custom template that replaces the default PURCHASE (Track Transaction) template. You should see STATIC_TRACK_TRANSACTION as an event under the <strong>Postback Config</strong> in the Criteo Partner Manager UI. You can copy the postback template from STATIC_TRACK_TRANSACTION, and paste it into the PURCHASE postback, replacing the previous postback. Click Save at the bottom of the screen, and you&#39;re good to go!</p><h2 id="send-dates-for-travel-campaigns" tabindex="-1">Send dates for travel campaigns <a class="header-anchor" href="#send-dates-for-travel-campaigns" aria-label="Permalink to &quot;Send dates for travel campaigns&quot;">​</a></h2><p>Criteo can optimize campaigns based on travel search dates. To report travel search dates to Criteo, follow these steps:</p><ol><li>In your app, add custom metadata to your events with keys din and dout, and a date string in format &#39;YYYY-MM-DD&#39; for the date of the inbound and outbound flight respectively.</li><li>In the Branch dashboard, navigate to Postback Config within the Criteo entry of the Ads Partner Manager.</li><li>Find the postback you want to edit, and add the following string in the relevant place. For VIEW_ITEM for example, it&#39;s another event in the events array.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{&quot;event&quot;:&quot;vs&quot;,&quot;din&quot;:&lt;@json&gt;\${(custom_data.din)!}&lt;/@json&gt;,&quot;dout&quot;:&lt;@json&gt;\${(custom_data.dout)!}&lt;/@json&gt;}</span></span></code></pre></div><h2 id="send-hashed-emails" tabindex="-1">Send hashed emails <a class="header-anchor" href="#send-hashed-emails" aria-label="Permalink to &quot;Send hashed emails&quot;">​</a></h2><p>Criteo accepts hashed emails from your ad campaigns. To send hashed emails, please follow the below logic.</p><ol><li>In your app, add <a href="./criteo.html#branch-and-criteo-event-mapping">custom metadata</a> to your events with keys <code>md5_hashed_email</code>, and a value of an MD5 hashed email address. Please do not send unhashed emails to Branch.</li><li>In the Branch dashboard, navigate to Postback Config within the Criteo entry of the Ads Partner Manager.</li><li>Find the postback you want to edit, and add the following string in the relevant place. This will generally be as another event in the <code>&quot;events&quot;</code> array. Please note that _OPEN _and _INSTALL _events do not support this parameter.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{&quot;event&quot;:&quot;setHashedEmail&quot;, &quot;email&quot;:[&lt;@json&gt;\${(custom_data.md5_hashed_email)!}&lt;/@json&gt;]}</span></span></code></pre></div><h2 id="send-non-branch-deep-links" tabindex="-1">Send non-Branch deep links <a class="header-anchor" href="#send-non-branch-deep-links" aria-label="Permalink to &quot;Send non-Branch deep links&quot;">​</a></h2><p>Criteo requests all deep links (including non-Branch Links) to be sent to their servers upon app open. Branch doesn&#39;t provide this by default, so you&#39;ll need to update your SDK initialization to support this.</p><p><strong>If you use any authentication or login libraries, please ensure you strip out all tokens, passwords and other sensitive information before passing this information to Branch.</strong></p><p>To pass the <code>$criteo_deep_link_url</code> to Branch, add this code to your AppDelegate or the relevant Activity/Application. You may already have some of this code inside you files, so simply copy the relevant Branch pieces.</p><p><strong>iOS</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- (BOOL)application:(UIApplication *)application</span></span>
<span class="line"><span>        continueUserActivity:(NSUserActivity *)userActivity</span></span>
<span class="line"><span>        restorationHandler:(void (^)(NSArray *))restorationHandler {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        // NOTE: you should sanitize and ensure no sensitive is passed from</span></span>
<span class="line"><span>        // userActivity.webpageURL.absolutelString.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        [[Branch getInstance] setRequestMetadataKey:@&quot;$criteo_deep_link_url&quot; value:userActivity.webpageURL.absoluteString];</span></span>
<span class="line"><span>        [[Branch getInstance] continueUserActivity:userActivity];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        // Process non-Branch userActivities here...</span></span>
<span class="line"><span>        return YES;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        - (BOOL)application:(UIApplication *)application</span></span>
<span class="line"><span>        openURL:(NSURL *)url</span></span>
<span class="line"><span>        sourceApplication:(NSString *)sourceApplication</span></span>
<span class="line"><span>        annotation:(id)annotation {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        // NOTE: you should sanitize and ensure no sensitive is passed from</span></span>
<span class="line"><span>        // url.absolutelString.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        [[Branch getInstance] setRequestMetadataKey:@&quot;$criteo_deep_link_url&quot; value:url.absoluteString];</span></span>
<span class="line"><span>        // Required. Returns YES if Branch link, else returns NO</span></span>
<span class="line"><span>        [[Branch getInstance]</span></span>
<span class="line"><span>        application:application</span></span>
<span class="line"><span>        openURL:url</span></span>
<span class="line"><span>        sourceApplication:sourceApplication</span></span>
<span class="line"><span>        annotation:annotation];</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        // Process non-Branch URIs here...</span></span>
<span class="line"><span>        return YES;</span></span>
<span class="line"><span>        }</span></span></code></pre></div><p><strong>Android</strong></p><p>Before you initialize in your Application <code>onCreate</code> or Deep Link Activity&#39;s <code>onStart</code>.<br> You will want to persist the value from <code>onCreate</code>, or <code>onNewIntent</code>. mIntentData is a String field defined in the activity.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Override</span></span>
<span class="line"><span>        protected void onCreate() {</span></span>
<span class="line"><span>        // NOTE: be sure to remove sensitive / PII data from the intent data coming in.</span></span>
<span class="line"><span>        mIntentData = this.getIntent().getData().toString();</span></span>
<span class="line"><span>        // other operations below</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        @Override</span></span>
<span class="line"><span>        public void onNewIntent(Intent intent) {</span></span>
<span class="line"><span>        // NOTE: be sure to remove sensitive / PII data from the intent data coming in.</span></span>
<span class="line"><span>        mIntentData = this.getIntent().getData().toString();</span></span>
<span class="line"><span>        // other operations below</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        Branch.getInstance().setRequestMetadata(&quot;&quot;$criteo_deep_link_url&quot;&quot;, mIntentData);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        Branch.sessionBuilder(this)...init();</span></span></code></pre></div><h2 id="identify-users-with-setidentity" tabindex="-1">Identify users with setIdentity <a class="header-anchor" href="#identify-users-with-setidentity" aria-label="Permalink to &quot;Identify users with setIdentity&quot;">​</a></h2><p>Branch allows you to identify your users and will send those user identities to Criteo.</p><p>The method used to identify users is called <code>setIdentity</code>, and the value you set is called the <code>developer_identity</code>. Set this upon a user login event in your app, and Branch will use it for all subsequent events attributed to that user.</p><p><a href="./android-advanced-features.html#section-track-users">Android</a><br><a href="./android-advanced-features.html#section-track-users">iOS</a></p><div class="danger custom-block"><p class="custom-block-title">Do not send emails or PII with setIdentity</p><p>To respect user privacy, please do not use names, emails or other identifiable information as your developer identity.</p></div><h3 id="branch-and-criteo-event-mapping" tabindex="-1">Branch and Criteo event mapping <a class="header-anchor" href="#branch-and-criteo-event-mapping" aria-label="Permalink to &quot;Branch and Criteo event mapping&quot;">​</a></h3><p>Branch supports the full suite of Criteo events. Please talk to your Criteo Solutions Engineer to ensure you&#39;ve identified the right events for your app.</p><p>Important implementation details</p><ul><li>For events with Branch Event Categorization of &quot;Custom Event,&quot; you must name the event as laid out in the below table.</li><li>For events with Additional Metadata Keys, you must set the Custom Data on the event with a specific key so the postback is configured correctly for you.</li></ul><p>For example, for &quot;UI_STATUS&quot; the code snippet looks like this:</p><p><strong>iOS</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchEvent *event = [BranchEvent customEventWithName:@&quot;UI_STATUS&quot;];</span></span>
<span class="line"><span>        event.customData = (NSMutableDictionary*) @{</span></span>
<span class="line"><span>        &quot;ui_status&quot;: &quot;subscriber&quot;</span></span>
<span class="line"><span>        };</span></span>
<span class="line"><span>        event.logEvent() // Log the event.</span></span></code></pre></div><p><strong>Android</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>new BranchEvent(&quot;UI_STATUS&quot;)</span></span>
<span class="line"><span>        .addCustomDataProperty(&quot;ui_status&quot;, &quot;subscriber&quot;)</span></span>
<span class="line"><span>        .logEvent(MainActivity.this);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Branch Event Name</th><th>Criteo Name</th><th>Branch Event Categorization</th><th>Additional Metadata Keys</th></tr></thead><tbody><tr><td>OPEN</td><td>View Home &amp; appDeeplink</td><td>SDK Default</td><td><code>$criteo_deep_link_url</code></td></tr><tr><td>INSTALL</td><td>Install</td><td>SDK Default</td><td>None</td></tr><tr><td>VIEW_ITEMS</td><td>View Listing</td><td>Content Event</td><td>None</td></tr><tr><td>VIEW_ITEM</td><td>View Product</td><td>Content Event</td><td>None</td></tr><tr><td>VIEW_CART</td><td>View Basket</td><td>Commerce Event</td><td>None</td></tr><tr><td>PURCHASE</td><td>Track Transaction</td><td>Commerce Event</td><td>None</td></tr><tr><td>PURCHASE*</td><td>Static Track Transaction</td><td>Commerce Event</td><td>None</td></tr><tr><td>ACHIEVE_LEVEL</td><td>UI Level</td><td>User Lifecycle Event</td><td><code>ui_level</code></td></tr><tr><td>UNLOCK_ACHIEVEMENT</td><td>UI Achievement</td><td>User Lifecycle Event</td><td><code>ui_achievement</code></td></tr><tr><td>COMPLETE_REGISTRATION</td><td>Registration</td><td>User Lifecycle Event</td><td>None</td></tr><tr><td>COMPLETE_TUTORIAL</td><td>Tutorial Finished</td><td>User Lifecycle Event</td><td>None</td></tr><tr><td>UI_STATUS</td><td>UI Status</td><td><strong>Custom Event</strong></td><td><code>ui_status</code></td></tr><tr><td>UI_LOGIN</td><td>UI Login</td><td><strong>Custom Event</strong></td><td>None</td></tr><tr><td>SUBSCRIPTION</td><td>Subscription</td><td><strong>Custom Event</strong></td><td>None</td></tr><tr><td>LOW_PRIORITY</td><td>Low Priority</td><td><strong>Custom Event</strong></td><td>None</td></tr><tr><td>HIGH_PRIORITY</td><td>High Priority</td><td><strong>Custom Event</strong></td><td>None</td></tr><tr><td>ABANDONED_BASKET</td><td>Abandoned Basket</td><td><strong>Custom Event</strong></td><td>None</td></tr></tbody></table><p>The Static Track Transaction Postback is available as a custom version of the PURCHASE postback. Please see <a href="./criteo.html#add-static-track-transaction">Add Static Track Transaction</a> for setup.</p>`,42)])])}const v=e(i,[["render",o]]);export{h as __pageData,v as default};
